-- Habilitar inserção caso precise de IDs específicos
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Publicidade Profissional', 
  'Médio', 
  'O advogado José decidiu impulsionar publicações no Instagram para divulgar seus artigos jurídicos sobre direito tributário. Visando ampliar sua clientela, ele inseriu um link direto para agendamento de consultas com a frase: "Agende sua consulta com desconto especial de 20%". À luz do Provimento 205/2021 da OAB, assinale a opção correta:', 
  ARRAY['"A publicidade ativa e o patrocínio de postagens (tráfego pago) são permitidos, mas a oferta de descontos e a mercantilização da advocacia são vedadas."', '"A publicidade profissional do advogado tem caráter puramente mercantil, sendo permitida a divulgação livre de preços e descontos nas redes sociais."', '"O patrocínio de postagens nas redes sociais é vedado em qualquer circunstância pela OAB, caracterizando captação ilegal de clientela."', '"É permitido divulgar descontos em consultas, desde que a divulgação ocorra exclusivamente em ambiente digital (internet)."'], 
  0, 
  'De acordo com o Provimento 205/2021, o marketing de conteúdos jurídicos e o tráfego pago são permitidos, porém, a publicidade deve primar pela sobriedade e caráter informativo, sendo expressamente proibida a mercantilização (como oferta de descontos e captação ativa de clientela).', 
  (SELECT id FROM disciplinas WHERE nome = 'Ética Profissional' LIMIT 1)
);
