INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Infrações e Sanções Disciplinares', 
  'Médio', 
  'O advogado Gabriel reteve abusivamente os autos de um processo judicial, deixando de devolvê-los no prazo legal mesmo após ter sido devidamente intimado. De acordo com as normas disciplinares da OAB, essa conduta caracteriza infração disciplinar punível com:', 
  ARRAY['"Suspensão do exercício profissional."', '"Censura simples."', '"Exclusão definitiva dos quadros da OAB."', '"Multa de até dez anuidades."'], 
  0, 
  'O Art. 34, XXII c/c Art. 37, I da Lei 8.906/94 estabelece que reter abusivamente autos de processos enseja a sanção de suspensão.', 
  (SELECT id FROM disciplinas WHERE nome = 'Ética Profissional' LIMIT 1)
);
