INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Sociedade de Advogados', 
  'Médio', 
  'Os advogados Felipe e Gabriela pretendem constituir uma Sociedade Unipessoal de Advocacia. A respeito das regras de constituição e atuação dessa modalidade societária, assinale a afirmativa correta:', 
  ARRAY['"O advogado não pode integrar mais de uma sociedade de advogados ou sociedade unipessoal com sede ou filial na mesma área de conselho seccional."', '"A sociedade unipessoal pode adotar nome de fantasia para facilitar o marketing digital."', '"É permitido que a sociedade unipessoal inclua sócio de serviço que seja bacharel em Direito não inscrito nos quadros da OAB."', '"A sociedade unipessoal responde subsidiariamente, de forma limitada, pelas obrigações decorrentes de danos causados a clientes."'], 
  0, 
  'O Art. 15, § 4º da Lei 8.906/94 proíbe o advogado de integrar mais de uma sociedade de advogados, constituir mais de uma sociedade unipessoal ou integrar, simultaneamente, ambas, na mesma área territorial do Conselho Seccional.', 
  (SELECT id FROM disciplinas WHERE nome = 'Ética Profissional' LIMIT 1)
);
