INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Órgãos da OAB', 
  'Médio', 
  'A respeito da estrutura organizacional da OAB e da competência de seus órgãos, assinale a opção correta:', 
  ARRAY['"O Conselho Federal da OAB é o órgão supremo da entidade, possuindo personalidade jurídica própria, com sede em Brasília/DF."', '"A Caixa de Assistência dos Advogados possui personalidade jurídica independente dos Conselhos Seccionais, não prestando contas a eles."', '"As Subseções da OAB possuem personalidade jurídica própria e autonomia financeira irrestrita."', '"Apenas a Seccional Estadual pode interpor recurso de decisões disciplinares perante os tribunais de justiça estaduais."'], 
  0, 
  'Conforme o Art. 45 da Lei 8.906/94, a OAB é composta pelo Conselho Federal (personalidade jurídica própria, sede no Distrito Federal), Conselhos Seccionais, Subseções e Caixas de Assistência.', 
  (SELECT id FROM disciplinas WHERE nome = 'Ética Profissional' LIMIT 1)
);
