INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Sigilo Profissional', 
  'Fácil', 
  'O advogado Gabriel foi intimado a depor como testemunha em processo penal sobre fatos sigilosos que lhe foram revelados por um cliente sob o manto do segredo profissional. Nesse cenário, o advogado:', 
  ARRAY['"Deve recusar-se a depor, pois o sigilo profissional é um direito e um dever legal do advogado, mesmo se autorizado pelo cliente."', '"É obrigado a depor, uma vez que a intimação judicial sobrepõe-se às regras de ética da advocacia."', '"Pode depor apenas sobre fatos secundários que não envolvam a autoria delitiva do cliente."', '"Fica obrigado a depor se o crime investigado for punido com pena de reclusão superior a quatro anos."'], 
  0, 
  'O Art. 7º, XIX do Estatuto da OAB garante ao advogado a prerrogativa de recusar-se a depor como testemunha sobre fatos de que tenha tomado conhecimento no exercício profissional.', 
  (SELECT id FROM disciplinas WHERE nome = 'Ética Profissional' LIMIT 1)
);
