INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Processo Disciplinar na OAB', 
  'Difícil', 
  'Contra o advogado José foi instaurada representação disciplinar perante o Tribunal de Ética e Disciplina (TED) da OAB. A respeito do rito processual disciplinar, assinale a opção correta:', 
  ARRAY['"O processo disciplinar tramita em sigilo, só tendo acesso às suas informações as partes, seus defensores e a autoridade julgadora."', '"A representação disciplinar não pode ser instaurada de ofício, exigindo sempre denúncia formal por escrito da vítima."', '"O prazo de prescrição da pretensão punitiva da OAB é de dez anos contados da data do fato."', '"A apelação das decisões finais do TED é enviada diretamente ao Poder Judiciário (Justiça Federal)."'], 
  0, 
  'O Art. 72 da Lei 8.906/94 estabelece que o processo disciplinar tramita em sigilo, até o seu término, para resguardar a honra profissional do representado.', 
  (SELECT id FROM disciplinas WHERE nome = 'Ética Profissional' LIMIT 1)
);
