INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Remédios Constitucionais', 
  'Médio', 
  'Maria impetrou ação constitucional para ter acesso a relatórios informativos contendo dados sobre sua própria pessoa armazenados em banco de dados da Receita Federal. O pleito foi negado na via administrativa. A ação cabível é:', 
  ARRAY['"Habeas Data."', '"Mandado de Segurança."', '"Ação Civil Pública."', '"Ação Popular."'], 
  0, 
  'O Habeas Data (Art. 5º, LXXII da CF/88) é o remédio constitucional adequado para assegurar o conhecimento de informações relativas à pessoa do impetrante constantes de registros governamentais.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Constitucional' LIMIT 1)
);
