INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Remédios Constitucionais', 
  'Médio', 
  'Camila impetrou ação constitucional para ter acesso a relatórios informativos contendo dados sobre sua própria pessoa armazenados em banco de dados da Receita Federal. O pleito foi negado na via administrativa. A ação cabível é:', 
