INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Processo Legislativo', 
  'Difícil', 
  'Uma proposta de Emenda à Constituição (PEC) que visa abolir as garantias individuais da liberdade de expressão e de manifestação do pensamento é apresentada no Senado. Sobre essa PEC, assinale a afirmativa correta:', 
  ARRAY['"A PEC não pode sequer ser objeto de deliberação, pois visa abolir direitos e garantias individuais (cláusula pétrea)."', '"A PEC é formalmente e materialmente válida, podendo ser aprovada por maioria simples."', '"A matéria de emenda constitucional rejeitada poderá ser reapresentada na mesma sessão legislativa por maioria absoluta."', '"A PEC só pode prosseguir se houver sanção do Presidente da República."'], 
  0, 
  'O Art. 60, § 4º, IV da CF/88 veda a deliberação de propostas de emenda tendentes a abolir direitos e garantias individuais (cláusulas pétreas).', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Constitucional' LIMIT 1)
);
