INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Controle de Constitucionalidade', 
  'Difícil', 
  'Um governador de estado pretende questionar a constitucionalidade de uma lei federal recém-promulgada. A respeito dos legitimados ativos universais para propositura de Ação Direta de Inconstitucionalidade (ADI), assinale a afirmativa correta:', 
  ARRAY['"Governador de Estado e do Distrito Federal é legitimado especial, necessitando comprovar pertinência temática com a lei federal."', '"Governador de Estado é legitimado universal, dispensando a demonstração de interesse jurídico direto."', '"Partidos políticos sem representação no Congresso Nacional podem ajuizar ADI se houver aval do PGR."', '"Mesas de Câmaras Municipais têm legitimidade para propor ADI no STF."'], 
  0, 
  'Embora o governador figure no rol do Art. 103 da CF, a jurisprudência consolidada do STF o classifica como legitimado especial, exigindo a demonstração de pertinência temática para as ações cíveis federais.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Constitucional' LIMIT 1)
);
