INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Organização do Estado', 
  'Médio', 
  'O Estado X editou lei ordinária dispondo sobre diretrizes de trânsito e transporte urbano dentro do seu território. Diante da repartição de competências legislativas prevista na CF/88, tal lei estadual é:', 
  ARRAY['"Inconstitucional, pois legislar sobre trânsito e transporte é competência legislativa privativa da União."', '"Constitucional, por se tratar de competência comum concorrente entre União e Estados."', '"Constitucional, desde que respeitadas as normas gerais do Município."', '"Inconstitucional, pois trânsito é de competência privativa dos Municípios."'], 
  0, 
  'De acordo com o Art. 22, XI da CF/88, compete privativamente à União legislar sobre trânsito e transporte, gerando inconstitucionalidade formal orgânica a lei estadual.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Constitucional' LIMIT 1)
);
