INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Direitos e Garantias Fundamentais', 
  'Fácil', 
  'Policiais militares ingressaram na residência de Gabriel durante a noite, sem autorização judicial, sob a alegação de suspeita de crime de estelionato cometido dias atrás. À luz do princípio da inviolabilidade do domicílio (Art. 5º, XI, CF):', 
  ARRAY['"A atuação dos policiais é ilícita, pois a entrada forçada na residência durante a noite exige consentimento ou flagrante delito/desastre/socorro, ou determinação judicial apenas durante o dia."', '"A invasão domiciliar é válida a qualquer hora do dia ou da noite sob suspeita de qualquer ilícito penal."', '"A determinação judicial autoriza a entrada domiciliar a qualquer hora da noite."', '"A residência não goza de proteção constitucional em áreas de periferia urbana."'], 
  0, 
  'A casa é asilo inviolável, ninguém nela podendo penetrar sem consentimento, salvo em caso de flagrante delito, desastre, socorro, ou por determinação judicial durante o dia (Art. 5º, XI).', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Constitucional' LIMIT 1)
);
