INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Poder Executivo', 
  'Médio', 
  'Em caso de vacância dos cargos de Presidente e Vice-Presidente da República nos dois primeiros anos do mandato presidencial, a linha sucessória estabelecida pela Constituição determina que assumirá provisoriamente:', 
  ARRAY['"O Presidente da Câmara dos Deputados, que deverá convocar eleições diretas em noventa dias."', '"O Presidente do Senado Federal, que exercerá o mandato até o fim do quadriênio."', '"O Presidente do STF, convocando eleições indiretas pelo Congresso Nacional."', '"O Ministro da Defesa, instalando junta governativa militar."'], 
  0, 
  'Conforme o Art. 80 e 81 da CF/88, vagando os cargos de Presidente e Vice nos primeiros dois anos, o Presidente da Câmara é chamado ao exercício, devendo ocorrer eleições diretas em 90 dias.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Constitucional' LIMIT 1)
);
