INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Súmula Vinculante', 
  'Médio', 
  'A respeito do procedimento de aprovação, revisão ou cancelamento de Súmula Vinculante pelo Supremo Tribunal Federal, assinale a opção correta:', 
  ARRAY['"Exige decisão tomada por dois terços dos membros do STF, mediante provocação dos legitimados para a ADI."', '"Pode ser editada de ofício por maioria simples dos ministros do STF em sessão plenária."', '"Vincula a atuação do Poder Legislativo na sua função típica de legislar."', '"Não pode ser objeto de impugnação ou controle por cidadãos comuns."'], 
  0, 
  'A aprovação de Súmula Vinculante exige voto de 2/3 dos membros do STF (8 ministros) e tem eficácia vinculante em relação à Administração Pública e demais órgãos do Judiciário, sem vincular a função legislativa federal.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Constitucional' LIMIT 1)
);
