INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Poder Legislativo', 
  'Médio', 
  'Os deputados federais e senadores, desde a expedição do diploma, gozam de imunidade formal em relação à prisão. Nesse sentido, eles:', 
  ARRAY['"Não poderão ser presos, salvo em flagrante de crime inafiançável, caso em que os autos serão remetidos em vinte e quatro horas à respectiva Casa Legislativa."', '"Gozam de imunidade prisional civil e penal absoluta, impossibilitando qualquer espécie de segregação preventiva."', '"Só podem ser presos após trânsito em julgado de sentença condenatória proferida pelo STF, independentemente do tipo de crime."', '"Podem ser presos por ordem de qualquer juiz de primeira instância caso cometa ato de improbidade administrativa."'], 
  0, 
  'Conforme o Art. 53, § 2º da CF/88, os membros do Congresso Nacional não poderão ser presos, salvo em flagrante de crime inafiançável.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Constitucional' LIMIT 1)
);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Poder Legislativo', 
  'Médio', 
  'Os deputados federais e senadores, desde a expedição do diploma, gozam de imunidade formal em relação à prisão. Nesse sentido, eles:', 
  ARRAY['"Não poderão ser presos, salvo em flagrante de crime inafiançável, caso em que os autos serão remetidos em vinte e quatro horas à respectiva Casa Legislativa."', '"Gozam de imunidade prisional civil e penal absoluta, impossibilitando qualquer espécie de segregação preventiva."', '"Só podem ser presos após trânsito em julgado de sentença condenatória proferida pelo STF, independentemente do tipo de crime."', '"Podem ser presos por ordem de qualquer juiz de primeira instância caso cometa ato de improbidade administrativa."'], 
  0, 
  'Conforme o Art. 53, § 2º da CF/88, os membros do Congresso Nacional não poderão ser presos, salvo em flagrante de crime inafiançável.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Constitucional' LIMIT 1)
);
