INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Ordem Social e Educação', 
  'Fácil', 
  'A Constituição da República assegura a educação como direito de todos e dever do Estado e da família. Segundo a Carta Magna, o ensino público será ministrado com base no seguinte princípio:', 
  ARRAY['"Gratuidade do ensino público em estabelecimentos oficiais."', '"Monopólio de ideias e concepções pedagógicas estatais."', '"Centralização exclusiva do financiamento pela União."', '"Prevalência do ensino religioso obrigatório em todas as etapas escolares."'], 
  0, 
  'O Art. 206, IV da CF/88 estabelece como princípio do ensino a gratuidade do ensino público em estabelecimentos oficiais.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Constitucional' LIMIT 1)
);
