INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Atos Administrativos', 
  'Médio', 
  'Durante uma fiscalização no estabelecimento de Maria, constatou-se uma irregularidade administrativa. Em consequência, o agente aplicou uma sanção que Maria entende violar os princípios basilares da matéria. No tocante a Atos Administrativos, assinale a alternativa juridicamente correta:', 
  ARRAY['"A conduta é válida pois respeita estritamente as regras de Atos Administrativos previstas em lei específica."', '"A medida padece de nulidade absoluta por vício formal no tratamento de Atos Administrativos."', '"O instituto de Atos Administrativos não se aplica a entidades de direito público, apenas a relações privadas."', '"Configura-se desvio de finalidade por ausência de nexo causal no âmbito de Atos Administrativos."'], 
  0, 
  'No caso concreto, a conduta atende aos preceitos da legislação vigente aplicável a Atos Administrativos, respeitando os limites da legalidade e os princípios gerais de direito.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Administrativo' LIMIT 1)
);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Atos Administrativos', 
  'Médio', 
  'O cidadão João buscou assessoria jurídica para solucionar um conflito relativo a Atos Administrativos envolvendo uma entidade privada. Diante das regras vigentes e da jurisprudência consolidada, qual a orientação adequada a ser prestada a João?', 
  ARRAY['"Trata-se de direito líquido e certo assegurado de forma plena pelas normas de Atos Administrativos."', '"O pleito deve ser indeferido pois prescreveu o prazo legal para suscitar controvérsia sobre Atos Administrativos."', '"Exige-se comprovação de dolo ou culpa grave para verificar responsabilidade em sede de Atos Administrativos."', '"A matéria de Atos Administrativos exige procedimento administrativo prévio sob pena de carência de ação."'], 
  1, 
  'Conforme consolidado pelos tribunais superiores, os direitos relativos a Atos Administrativos exigem observância do devido processo legal e não admitem cobrança retroativa abusiva.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Administrativo' LIMIT 1)
);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Atos Administrativos', 
  'Médio', 
  'Em ação judicial discutindo especificamente o instituto de Atos Administrativos, a empresa X Ltda sustentou a inexigibilidade da obrigação alegada. Diante do quadro fático apresentado, assinale a opção que reflete o posicionamento correto sobre o tema:', 
  ARRAY['"A responsabilidade é subjetiva, recaindo o ônus da prova sobre a caracterização de Atos Administrativos."', '"A obrigação é solidária, respondendo todos os envolvidos nos limites de Atos Administrativos."', '"O descumprimento gera apenas sanção pecuniária simples sem direito a perdas e danos em Atos Administrativos."', '"Inexiste dever de indenizar se comprovada força maior superveniente em Atos Administrativos."'], 
  2, 
  'A obrigação em Atos Administrativos possui caráter pessoal e segue a regra geral de distribuição do ônus probatório, exigindo prova do nexo de causalidade direto.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Administrativo' LIMIT 1)
);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Atos Administrativos', 
  'Médio', 
  'Em recente acórdão, discutiu-se a aplicação das regras de Atos Administrativos em caso de grande repercussão nacional. À luz da doutrina majoritária e da legislação aplicável, assinale a afirmativa correta:', 
  ARRAY['"A jurisprudência do STJ e STF fixa que a competência para julgar causas de Atos Administrativos é exclusiva da Justiça Federal."', '"Admite-se flexibilização das regras de Atos Administrativos se demonstrado interesse social relevante."', '"O ato é plenamente revogável por razões de oportunidade e conveniência decorrentes de Atos Administrativos."', '"A aplicação de penalidade em Atos Administrativos exige notificação pessoal prévia e contraditório."'], 
  3, 
  'A jurisprudência pátria estabelece que a disciplina jurídica de Atos Administrativos visa garantir a segurança jurídica e a eficiência das relações contratuais ou sociais pactuadas.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Administrativo' LIMIT 1)
);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Atos Administrativos', 
  'Médio', 
  'A administração ou a parte interessada, representada pelo doutor Marcos, ajuizou a medida cabível para garantir o direito pretendido sobre Atos Administrativos. Diante disso, assinale a opção correta:', 
  ARRAY['"A pretensão está amparada na legalidade e na doutrina clássica aplicável a Atos Administrativos."', '"O direito caducou no prazo de cinco anos contados da ciência do fato referente a Atos Administrativos."', '"Não cabe ação rescisória para reformar julgado fundamentado na interpretação de Atos Administrativos."', '"A decisão administrativa faz coisa julgada material em relação a Atos Administrativos, impedindo revisão judicial."'], 
  0, 
  'O prazo decadencial aplicável ao caso é quinquenal, conforme expressa previsão legal, aplicando-se de forma direta sobre os atos decorrentes de Atos Administrativos.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Administrativo' LIMIT 1)
);
