  ARRAY['"A pretensão está amparada na legalidade e na doutrina clássica aplicável a Crimes contra a Administração Pública."', '"O direito caducou no prazo de cinco anos contados da ciência do fato referente a Crimes contra a Administração Pública."', '"Não cabe ação rescisória para reformar julgado fundamentado na interpretação de Crimes contra a Administração Pública."', '"A decisão administrativa faz coisa julgada material em relação a Crimes contra a Administração Pública, impedindo revisão judicial."'], 
  1, 
  'O prazo decadencial aplicável ao caso é quinquenal, conforme expressa previsão legal, aplicando-se de forma direta sobre os atos decorrentes de Crimes contra a Administração Pública.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Penal' LIMIT 1)
);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Penas e Dosimetria', 
  'Difícil', 
  'Durante uma fiscalização no estabelecimento de Paula, constatou-se uma irregularidade administrativa. Em consequência, o agente aplicou uma sanção que Paula entende violar os princípios basilares da matéria. No tocante a Penas e Dosimetria, assinale a alternativa juridicamente correta:', 
  ARRAY['"A conduta é válida pois respeita estritamente as regras de Penas e Dosimetria previstas em lei específica."', '"A medida padece de nulidade absoluta por vício formal no tratamento de Penas e Dosimetria."', '"O instituto de Penas e Dosimetria não se aplica a entidades de direito público, apenas a relações privadas."', '"Configura-se desvio de finalidade por ausência de nexo causal no âmbito de Penas e Dosimetria."'], 
  0, 
  'No caso concreto, a conduta atende aos preceitos da legislação vigente aplicável a Penas e Dosimetria, respeitando os limites da legalidade e os princípios gerais de direito.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Penal' LIMIT 1)
);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Penas e Dosimetria', 
  'Difícil', 
  'O cidadão Gustavo buscou assessoria jurídica para solucionar um conflito relativo a Penas e Dosimetria envolvendo uma entidade privada. Diante das regras vigentes e da jurisprudência consolidada, qual a orientação adequada a ser prestada a Gustavo?', 
  ARRAY['"Trata-se de direito líquido e certo assegurado de forma plena pelas normas de Penas e Dosimetria."', '"O pleito deve ser indeferido pois prescreveu o prazo legal para suscitar controvérsia sobre Penas e Dosimetria."', '"Exige-se comprovação de dolo ou culpa grave para verificar responsabilidade em sede de Penas e Dosimetria."', '"A matéria de Penas e Dosimetria exige procedimento administrativo prévio sob pena de carência de ação."'], 
  1, 
  'Conforme consolidado pelos tribunais superiores, os direitos relativos a Penas e Dosimetria exigem observância do devido processo legal e não admitem cobrança retroativa abusiva.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Penal' LIMIT 1)
);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Penas e Dosimetria', 
  'Difícil', 
  'Em ação judicial discutindo especificamente o instituto de Penas e Dosimetria, a empresa X Ltda sustentou a inexigibilidade da obrigação alegada. Diante do quadro fático apresentado, assinale a opção que reflete o posicionamento correto sobre o tema:', 
  ARRAY['"A responsabilidade é subjetiva, recaindo o ônus da prova sobre a caracterização de Penas e Dosimetria."', '"A obrigação é solidária, respondendo todos os envolvidos nos limites de Penas e Dosimetria."', '"O descumprimento gera apenas sanção pecuniária simples sem direito a perdas e danos em Penas e Dosimetria."', '"Inexiste dever de indenizar se comprovada força maior superveniente em Penas e Dosimetria."'], 
  2, 
  'A obrigação em Penas e Dosimetria possui caráter pessoal e segue a regra geral de distribuição do ônus probatório, exigindo prova do nexo de causalidade direto.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Penal' LIMIT 1)
);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Penas e Dosimetria', 
  'Difícil', 
  'Em recente acórdão, discutiu-se a aplicação das regras de Penas e Dosimetria em caso de grande repercussão nacional. À luz da doutrina majoritária e da legislação aplicável, assinale a afirmativa correta:', 
  ARRAY['"A jurisprudência do STJ e STF fixa que a competência para julgar causas de Penas e Dosimetria é exclusiva da Justiça Federal."', '"Admite-se flexibilização das regras de Penas e Dosimetria se demonstrado interesse social relevante."', '"O ato é plenamente revogável por razões de oportunidade e conveniência decorrentes de Penas e Dosimetria."', '"A aplicação de penalidade em Penas e Dosimetria exige notificação pessoal prévia e contraditório."'], 
  3, 
  'A jurisprudência pátria estabelece que a disciplina jurídica de Penas e Dosimetria visa garantir a segurança jurídica e a eficiência das relações contratuais ou sociais pactuadas.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Penal' LIMIT 1)
);
