  'No caso concreto, a conduta atende aos preceitos da legislação vigente aplicável a Habeas Corpus, respeitando os limites da legalidade e os princípios gerais de direito.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Processual Penal' LIMIT 1)
);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Habeas Corpus', 
  'Médio', 
  'O cidadão Bruno buscou assessoria jurídica para solucionar um conflito relativo a Habeas Corpus envolvendo uma entidade privada. Diante das regras vigentes e da jurisprudência consolidada, qual a orientação adequada a ser prestada a Bruno?', 
