INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Direitos Reais', 
  'Difícil', 
  'Em ação judicial discutindo especificamente o instituto de Direitos Reais, a empresa X Ltda sustentou a inexigibilidade da obrigação alegada. Diante do quadro fático apresentado, assinale a opção que reflete o posicionamento correto sobre o tema:', 
  ARRAY['"A responsabilidade é subjetiva, recaindo o ônus da prova sobre a caracterização de Direitos Reais."', '"A obrigação é solidária, respondendo todos os envolvidos nos limites de Direitos Reais."', '"O descumprimento gera apenas sanção pecuniária simples sem direito a perdas e danos em Direitos Reais."', '"Inexiste dever de indenizar se comprovada força maior superveniente em Direitos Reais."'], 
  2, 
  'A obrigação em Direitos Reais possui caráter pessoal e segue a regra geral de distribuição do ônus probatório, exigindo prova do nexo de causalidade direto.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Civil' LIMIT 1)
);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
