  ARRAY['"A conduta é válida pois respeita estritamente as regras de Sucessões previstas em lei específica."', '"A medida padece de nulidade absoluta por vício formal no tratamento de Sucessões."', '"O instituto de Sucessões não se aplica a entidades de direito público, apenas a relações privadas."', '"Configura-se desvio de finalidade por ausência de nexo causal no âmbito de Sucessões."'], 
  1, 
  'No caso concreto, a conduta atende aos preceitos da legislação vigente aplicável a Sucessões, respeitando os limites da legalidade e os princípios gerais de direito.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Civil' LIMIT 1)
);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Sucessões', 
  'Difícil', 
  'O cidadão Bruno buscou assessoria jurídica para solucionar um conflito relativo a Sucessões envolvendo uma entidade privada. Diante das regras vigentes e da jurisprudência consolidada, qual a orientação adequada a ser prestada a Bruno?', 
  ARRAY['"Trata-se de direito líquido e certo assegurado de forma plena pelas normas de Sucessões."', '"O pleito deve ser indeferido pois prescreveu o prazo legal para suscitar controvérsia sobre Sucessões."', '"Exige-se comprovação de dolo ou culpa grave para verificar responsabilidade em sede de Sucessões."', '"A matéria de Sucessões exige procedimento administrativo prévio sob pena de carência de ação."'], 
  2, 
  'Conforme consolidado pelos tribunais superiores, os direitos relativos a Sucessões exigem observância do devido processo legal e não admitem cobrança retroativa abusiva.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Civil' LIMIT 1)
);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Sucessões', 
  'Difícil', 
  'Em ação judicial discutindo especificamente o instituto de Sucessões, a empresa X Ltda sustentou a inexigibilidade da obrigação alegada. Diante do quadro fático apresentado, assinale a opção que reflete o posicionamento correto sobre o tema:', 
  ARRAY['"A responsabilidade é subjetiva, recaindo o ônus da prova sobre a caracterização de Sucessões."', '"A obrigação é solidária, respondendo todos os envolvidos nos limites de Sucessões."', '"O descumprimento gera apenas sanção pecuniária simples sem direito a perdas e danos em Sucessões."', '"Inexiste dever de indenizar se comprovada força maior superveniente em Sucessões."'], 
  3, 
  'A obrigação em Sucessões possui caráter pessoal e segue a regra geral de distribuição do ônus probatório, exigindo prova do nexo de causalidade direto.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Civil' LIMIT 1)
);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Sucessões', 
  'Difícil', 
  'Em recente acórdão, discutiu-se a aplicação das regras de Sucessões em caso de grande repercussão nacional. À luz da doutrina majoritária e da legislação aplicável, assinale a afirmativa correta:', 
  ARRAY['"A jurisprudência do STJ e STF fixa que a competência para julgar causas de Sucessões é exclusiva da Justiça Federal."', '"Admite-se flexibilização das regras de Sucessões se demonstrado interesse social relevante."', '"O ato é plenamente revogável por razões de oportunidade e conveniência decorrentes de Sucessões."', '"A aplicação de penalidade em Sucessões exige notificação pessoal prévia e contraditório."'], 
  0, 
  'A jurisprudência pátria estabelece que a disciplina jurídica de Sucessões visa garantir a segurança jurídica e a eficiência das relações contratuais ou sociais pactuadas.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Civil' LIMIT 1)
);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Sucessões', 
  'Difícil', 
  'A administração ou a parte interessada, representada pelo doutor Lucas, ajuizou a medida cabível para garantir o direito pretendido sobre Sucessões. Diante disso, assinale a opção correta:', 
  ARRAY['"A pretensão está amparada na legalidade e na doutrina clássica aplicável a Sucessões."', '"O direito caducou no prazo de cinco anos contados da ciência do fato referente a Sucessões."', '"Não cabe ação rescisória para reformar julgado fundamentado na interpretação de Sucessões."', '"A decisão administrativa faz coisa julgada material em relação a Sucessões, impedindo revisão judicial."'], 
  1, 
  'O prazo decadencial aplicável ao caso é quinquenal, conforme expressa previsão legal, aplicando-se de forma direta sobre os atos decorrentes de Sucessões.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Civil' LIMIT 1)
);
