INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Extinção do Contrato', 
  'Médio', 
  'Em recente acórdão, discutiu-se a aplicação das regras de Extinção do Contrato em caso de grande repercussão nacional. À luz da doutrina majoritária e da legislação aplicável, assinale a afirmativa correta:', 
