);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Terceirização', 
  'Difícil', 
  'Em recente acórdão, discutiu-se a aplicação das regras de Terceirização em caso de grande repercussão nacional. À luz da doutrina majoritária e da legislação aplicável, assinale a afirmativa correta:', 
  ARRAY['"A jurisprudência do STJ e STF fixa que a competência para julgar causas de Terceirização é exclusiva da Justiça Federal."', '"Admite-se flexibilização das regras de Terceirização se demonstrado interesse social relevante."', '"O ato é plenamente revogável por razões de oportunidade e conveniência decorrentes de Terceirização."', '"A aplicação de penalidade em Terceirização exige notificação pessoal prévia e contraditório."'], 
