);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Terceirização', 
  'Difícil', 
  'A administração ou a parte interessada, representada pelo doutor Lucas, ajuizou a medida cabível para garantir o direito pretendido sobre Terceirização. Diante disso, assinale a opção correta:', 
  ARRAY['"A pretensão está amparada na legalidade e na doutrina clássica aplicável a Terceirização."', '"O direito caducou no prazo de cinco anos contados da ciência do fato referente a Terceirização."', '"Não cabe ação rescisória para reformar julgado fundamentado na interpretação de Terceirização."', '"A decisão administrativa faz coisa julgada material em relação a Terceirização, impedindo revisão judicial."'], 
  1, 
  'O prazo decadencial aplicável ao caso é quinquenal, conforme expressa previsão legal, aplicando-se de forma direta sobre os atos decorrentes de Terceirização.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito do Trabalho' LIMIT 1)
);
