INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Férias', 
  'Fácil', 
  'Em recente acórdão, discutiu-se a aplicação das regras de Férias em caso de grande repercussão nacional. À luz da doutrina majoritária e da legislação aplicável, assinale a afirmativa correta:', 
  ARRAY['"A jurisprudência do STJ e STF fixa que a competência para julgar causas de Férias é exclusiva da Justiça Federal."', '"Admite-se flexibilização das regras de Férias se demonstrado interesse social relevante."', '"O ato é plenamente revogável por razões de oportunidade e conveniência decorrentes de Férias."', '"A aplicação de penalidade em Férias exige notificação pessoal prévia e contraditório."'], 
  0, 
  'A jurisprudência pátria estabelece que a disciplina jurídica de Férias visa garantir a segurança jurídica e a eficiência das relações contratuais ou sociais pactuadas.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito do Trabalho' LIMIT 1)
);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
