);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Segurança e Medicina do Trabalho', 
  'Médio', 
  'Durante uma fiscalização no estabelecimento de Maria, constatou-se uma irregularidade administrativa. Em consequência, o agente aplicou uma sanção que Maria entende violar os princípios basilares da matéria. No tocante a Segurança e Medicina do Trabalho, assinale a alternativa juridicamente correta:', 
  ARRAY['"A conduta é válida pois respeita estritamente as regras de Segurança e Medicina do Trabalho previstas em lei específica."', '"A medida padece de nulidade absoluta por vício formal no tratamento de Segurança e Medicina do Trabalho."', '"O instituto de Segurança e Medicina do Trabalho não se aplica a entidades de direito público, apenas a relações privadas."', '"Configura-se desvio de finalidade por ausência de nexo causal no âmbito de Segurança e Medicina do Trabalho."'], 
  0, 
  'No caso concreto, a conduta atende aos preceitos da legislação vigente aplicável a Segurança e Medicina do Trabalho, respeitando os limites da legalidade e os princípios gerais de direito.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito do Trabalho' LIMIT 1)
);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
