);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Audiência Trabalhista', 
  'Médio', 
  'Em ação judicial discutindo especificamente o instituto de Audiência Trabalhista, a empresa X Ltda sustentou a inexigibilidade da obrigação alegada. Diante do quadro fático apresentado, assinale a opção que reflete o posicionamento correto sobre o tema:', 
  ARRAY['"A responsabilidade é subjetiva, recaindo o ônus da prova sobre a caracterização de Audiência Trabalhista."', '"A obrigação é solidária, respondendo todos os envolvidos nos limites de Audiência Trabalhista."', '"O descumprimento gera apenas sanção pecuniária simples sem direito a perdas e danos em Audiência Trabalhista."', '"Inexiste dever de indenizar se comprovada força maior superveniente em Audiência Trabalhista."'], 
  2, 
  'A obrigação em Audiência Trabalhista possui caráter pessoal e segue a regra geral de distribuição do ônus probatório, exigindo prova do nexo de causalidade direto.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Processual do Trabalho' LIMIT 1)
);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Audiência Trabalhista', 
  'Médio', 
  'Em recente acórdão, discutiu-se a aplicação das regras de Audiência Trabalhista em caso de grande repercussão nacional. À luz da doutrina majoritária e da legislação aplicável, assinale a afirmativa correta:', 
  ARRAY['"A jurisprudência do STJ e STF fixa que a competência para julgar causas de Audiência Trabalhista é exclusiva da Justiça Federal."', '"Admite-se flexibilização das regras de Audiência Trabalhista se demonstrado interesse social relevante."', '"O ato é plenamente revogável por razões de oportunidade e conveniência decorrentes de Audiência Trabalhista."', '"A aplicação de penalidade em Audiência Trabalhista exige notificação pessoal prévia e contraditório."'], 
  3, 
  'A jurisprudência pátria estabelece que a disciplina jurídica de Audiência Trabalhista visa garantir a segurança jurídica e a eficiência das relações contratuais ou sociais pactuadas.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Processual do Trabalho' LIMIT 1)
);
