INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Provas no Processo Trabalho', 
  'Médio', 
  'O cidadão Bruno buscou assessoria jurídica para solucionar um conflito relativo a Provas no Processo Trabalho envolvendo uma entidade privada. Diante das regras vigentes e da jurisprudência consolidada, qual a orientação adequada a ser prestada a Bruno?', 
  ARRAY['"Trata-se de direito líquido e certo assegurado de forma plena pelas normas de Provas no Processo Trabalho."', '"O pleito deve ser indeferido pois prescreveu o prazo legal para suscitar controvérsia sobre Provas no Processo Trabalho."', '"Exige-se comprovação de dolo ou culpa grave para verificar responsabilidade em sede de Provas no Processo Trabalho."', '"A matéria de Provas no Processo Trabalho exige procedimento administrativo prévio sob pena de carência de ação."'], 
  1, 
  'Conforme consolidado pelos tribunais superiores, os direitos relativos a Provas no Processo Trabalho exigem observância do devido processo legal e não admitem cobrança retroativa abusiva.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Processual do Trabalho' LIMIT 1)
);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Provas no Processo Trabalho', 
  'Médio', 
  'Em ação judicial discutindo especificamente o instituto de Provas no Processo Trabalho, a empresa X Ltda sustentou a inexigibilidade da obrigação alegada. Diante do quadro fático apresentado, assinale a opção que reflete o posicionamento correto sobre o tema:', 
  ARRAY['"A responsabilidade é subjetiva, recaindo o ônus da prova sobre a caracterização de Provas no Processo Trabalho."', '"A obrigação é solidária, respondendo todos os envolvidos nos limites de Provas no Processo Trabalho."', '"O descumprimento gera apenas sanção pecuniária simples sem direito a perdas e danos em Provas no Processo Trabalho."', '"Inexiste dever de indenizar se comprovada força maior superveniente em Provas no Processo Trabalho."'], 
  2, 
  'A obrigação em Provas no Processo Trabalho possui caráter pessoal e segue a regra geral de distribuição do ônus probatório, exigindo prova do nexo de causalidade direto.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Processual do Trabalho' LIMIT 1)
);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Provas no Processo Trabalho', 
  'Médio', 
  'Em recente acórdão, discutiu-se a aplicação das regras de Provas no Processo Trabalho em caso de grande repercussão nacional. À luz da doutrina majoritária e da legislação aplicável, assinale a afirmativa correta:', 
  ARRAY['"A jurisprudência do STJ e STF fixa que a competência para julgar causas de Provas no Processo Trabalho é exclusiva da Justiça Federal."', '"Admite-se flexibilização das regras de Provas no Processo Trabalho se demonstrado interesse social relevante."', '"O ato é plenamente revogável por razões de oportunidade e conveniência decorrentes de Provas no Processo Trabalho."', '"A aplicação de penalidade em Provas no Processo Trabalho exige notificação pessoal prévia e contraditório."'], 
  3, 
  'A jurisprudência pátria estabelece que a disciplina jurídica de Provas no Processo Trabalho visa garantir a segurança jurídica e a eficiência das relações contratuais ou sociais pactuadas.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Processual do Trabalho' LIMIT 1)
);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Provas no Processo Trabalho', 
  'Médio', 
  'A administração ou a parte interessada, representada pelo doutor Lucas, ajuizou a medida cabível para garantir o direito pretendido sobre Provas no Processo Trabalho. Diante disso, assinale a opção correta:', 
  ARRAY['"A pretensão está amparada na legalidade e na doutrina clássica aplicável a Provas no Processo Trabalho."', '"O direito caducou no prazo de cinco anos contados da ciência do fato referente a Provas no Processo Trabalho."', '"Não cabe ação rescisória para reformar julgado fundamentado na interpretação de Provas no Processo Trabalho."', '"A decisão administrativa faz coisa julgada material em relação a Provas no Processo Trabalho, impedindo revisão judicial."'], 
  0, 
  'O prazo decadencial aplicável ao caso é quinquenal, conforme expressa previsão legal, aplicando-se de forma direta sobre os atos decorrentes de Provas no Processo Trabalho.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Processual do Trabalho' LIMIT 1)
);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Provas no Processo Trabalho', 
  'Médio', 
  'Durante uma fiscalização no estabelecimento de Paula, constatou-se uma irregularidade administrativa. Em consequência, o agente aplicou uma sanção que Paula entende violar os princípios basilares da matéria. No tocante a Provas no Processo Trabalho, assinale a alternativa juridicamente correta:', 
  ARRAY['"A conduta é válida pois respeita estritamente as regras de Provas no Processo Trabalho previstas em lei específica."', '"A medida padece de nulidade absoluta por vício formal no tratamento de Provas no Processo Trabalho."', '"O instituto de Provas no Processo Trabalho não se aplica a entidades de direito público, apenas a relações privadas."', '"Configura-se desvio de finalidade por ausência de nexo causal no âmbito de Provas no Processo Trabalho."'], 
  1, 
  'No caso concreto, a conduta atende aos preceitos da legislação vigente aplicável a Provas no Processo Trabalho, respeitando os limites da legalidade e os princípios gerais de direito.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Processual do Trabalho' LIMIT 1)
);
