VALUES (
  'Títulos de Crédito', 
  'Difícil', 
  'Durante uma fiscalização no estabelecimento de Gabriela, constatou-se uma irregularidade administrativa. Em consequência, o agente aplicou uma sanção que Gabriela entende violar os princípios basilares da matéria. No tocante a Títulos de Crédito, assinale a alternativa juridicamente correta:', 
  ARRAY['"A conduta é válida pois respeita estritamente as regras de Títulos de Crédito previstas em lei específica."', '"A medida padece de nulidade absoluta por vício formal no tratamento de Títulos de Crédito."', '"O instituto de Títulos de Crédito não se aplica a entidades de direito público, apenas a relações privadas."', '"Configura-se desvio de finalidade por ausência de nexo causal no âmbito de Títulos de Crédito."'], 
  0, 
  'No caso concreto, a conduta atende aos preceitos da legislação vigente aplicável a Títulos de Crédito, respeitando os limites da legalidade e os princípios gerais de direito.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Empresarial' LIMIT 1)
);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Títulos de Crédito', 
  'Difícil', 
  'O cidadão Bruno buscou assessoria jurídica para solucionar um conflito relativo a Títulos de Crédito envolvendo uma entidade privada. Diante das regras vigentes e da jurisprudência consolidada, qual a orientação adequada a ser prestada a Bruno?', 
  ARRAY['"Trata-se de direito líquido e certo assegurado de forma plena pelas normas de Títulos de Crédito."', '"O pleito deve ser indeferido pois prescreveu o prazo legal para suscitar controvérsia sobre Títulos de Crédito."', '"Exige-se comprovação de dolo ou culpa grave para verificar responsabilidade em sede de Títulos de Crédito."', '"A matéria de Títulos de Crédito exige procedimento administrativo prévio sob pena de carência de ação."'], 
  1, 
  'Conforme consolidado pelos tribunais superiores, os direitos relativos a Títulos de Crédito exigem observância do devido processo legal e não admitem cobrança retroativa abusiva.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Empresarial' LIMIT 1)
);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Títulos de Crédito', 
  'Difícil', 
  'Em ação judicial discutindo especificamente o instituto de Títulos de Crédito, a empresa X Ltda sustentou a inexigibilidade da obrigação alegada. Diante do quadro fático apresentado, assinale a opção que reflete o posicionamento correto sobre o tema:', 
  ARRAY['"A responsabilidade é subjetiva, recaindo o ônus da prova sobre a caracterização de Títulos de Crédito."', '"A obrigação é solidária, respondendo todos os envolvidos nos limites de Títulos de Crédito."', '"O descumprimento gera apenas sanção pecuniária simples sem direito a perdas e danos em Títulos de Crédito."', '"Inexiste dever de indenizar se comprovada força maior superveniente em Títulos de Crédito."'], 
  2, 
  'A obrigação em Títulos de Crédito possui caráter pessoal e segue a regra geral de distribuição do ônus probatório, exigindo prova do nexo de causalidade direto.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Empresarial' LIMIT 1)
);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Títulos de Crédito', 
  'Difícil', 
  'Em recente acórdão, discutiu-se a aplicação das regras de Títulos de Crédito em caso de grande repercussão nacional. À luz da doutrina majoritária e da legislação aplicável, assinale a afirmativa correta:', 
  ARRAY['"A jurisprudência do STJ e STF fixa que a competência para julgar causas de Títulos de Crédito é exclusiva da Justiça Federal."', '"Admite-se flexibilização das regras de Títulos de Crédito se demonstrado interesse social relevante."', '"O ato é plenamente revogável por razões de oportunidade e conveniência decorrentes de Títulos de Crédito."', '"A aplicação de penalidade em Títulos de Crédito exige notificação pessoal prévia e contraditório."'], 
  3, 
  'A jurisprudência pátria estabelece que a disciplina jurídica de Títulos de Crédito visa garantir a segurança jurídica e a eficiência das relações contratuais ou sociais pactuadas.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Empresarial' LIMIT 1)
);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Títulos de Crédito', 
  'Difícil', 
  'A administração ou a parte interessada, representada pelo doutor Lucas, ajuizou a medida cabível para garantir o direito pretendido sobre Títulos de Crédito. Diante disso, assinale a opção correta:', 
  ARRAY['"A pretensão está amparada na legalidade e na doutrina clássica aplicável a Títulos de Crédito."', '"O direito caducou no prazo de cinco anos contados da ciência do fato referente a Títulos de Crédito."', '"Não cabe ação rescisória para reformar julgado fundamentado na interpretação de Títulos de Crédito."', '"A decisão administrativa faz coisa julgada material em relação a Títulos de Crédito, impedindo revisão judicial."'], 
  0, 
  'O prazo decadencial aplicável ao caso é quinquenal, conforme expressa previsão legal, aplicando-se de forma direta sobre os atos decorrentes de Títulos de Crédito.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Empresarial' LIMIT 1)
);
