INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Contratos Internacionais', 
  'Médio', 
  'Durante uma fiscalização no estabelecimento de Maria, constatou-se uma irregularidade administrativa. Em consequência, o agente aplicou uma sanção que Maria entende violar os princípios basilares da matéria. No tocante a Contratos Internacionais, assinale a alternativa juridicamente correta:', 
  ARRAY['"A conduta é válida pois respeita estritamente as regras de Contratos Internacionais previstas em lei específica."', '"A medida padece de nulidade absoluta por vício formal no tratamento de Contratos Internacionais."', '"O instituto de Contratos Internacionais não se aplica a entidades de direito público, apenas a relações privadas."', '"Configura-se desvio de finalidade por ausência de nexo causal no âmbito de Contratos Internacionais."'], 
  0, 
  'No caso concreto, a conduta atende aos preceitos da legislação vigente aplicável a Contratos Internacionais, respeitando os limites da legalidade e os princípios gerais de direito.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Internacional' LIMIT 1)
);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Contratos Internacionais', 
  'Médio', 
  'O cidadão João buscou assessoria jurídica para solucionar um conflito relativo a Contratos Internacionais envolvendo uma entidade privada. Diante das regras vigentes e da jurisprudência consolidada, qual a orientação adequada a ser prestada a João?', 
  ARRAY['"Trata-se de direito líquido e certo assegurado de forma plena pelas normas de Contratos Internacionais."', '"O pleito deve ser indeferido pois prescreveu o prazo legal para suscitar controvérsia sobre Contratos Internacionais."', '"Exige-se comprovação de dolo ou culpa grave para verificar responsabilidade em sede de Contratos Internacionais."', '"A matéria de Contratos Internacionais exige procedimento administrativo prévio sob pena de carência de ação."'], 
  1, 
  'Conforme consolidado pelos tribunais superiores, os direitos relativos a Contratos Internacionais exigem observância do devido processo legal e não admitem cobrança retroativa abusiva.', 
