INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Competência Internacional', 
  'Médio', 
  'Em recente acórdão, discutiu-se a aplicação das regras de Competência Internacional em caso de grande repercussão nacional. À luz da doutrina majoritária e da legislação aplicável, assinale a afirmativa correta:', 
