  ARRAY['"A responsabilidade é subjetiva, recaindo o ônus da prova sobre a caracterização de Imunidade de Jurisdição."', '"A obrigação é solidária, respondendo todos os envolvidos nos limites de Imunidade de Jurisdição."', '"O descumprimento gera apenas sanção pecuniária simples sem direito a perdas e danos em Imunidade de Jurisdição."', '"Inexiste dever de indenizar se comprovada força maior superveniente em Imunidade de Jurisdição."'], 
  2, 
  'A obrigação em Imunidade de Jurisdição possui caráter pessoal e segue a regra geral de distribuição do ônus probatório, exigindo prova do nexo de causalidade direto.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Internacional' LIMIT 1)
);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
