INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Imunidade de Jurisdição', 
  'Fácil', 
  'A administração ou a parte interessada, representada pelo doutor Lucas, ajuizou a medida cabível para garantir o direito pretendido sobre Imunidade de Jurisdição. Diante disso, assinale a opção correta:', 
