INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Organizações Internacionais', 
  'Médio', 
  'Durante uma fiscalização no estabelecimento de Maria, constatou-se uma irregularidade administrativa. Em consequência, o agente aplicou uma sanção que Maria entende violar os princípios basilares da matéria. No tocante a Organizações Internacionais, assinale a alternativa juridicamente correta:', 
  ARRAY['"A conduta é válida pois respeita estritamente as regras de Organizações Internacionais previstas em lei específica."', '"A medida padece de nulidade absoluta por vício formal no tratamento de Organizações Internacionais."', '"O instituto de Organizações Internacionais não se aplica a entidades de direito público, apenas a relações privadas."', '"Configura-se desvio de finalidade por ausência de nexo causal no âmbito de Organizações Internacionais."'], 
  0, 
  'No caso concreto, a conduta atende aos preceitos da legislação vigente aplicável a Organizações Internacionais, respeitando os limites da legalidade e os princípios gerais de direito.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Internacional' LIMIT 1)
);
