INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Competência Ambiental', 
  'Médio', 
  'Durante uma fiscalização no estabelecimento de Paula, constatou-se uma irregularidade administrativa. Em consequência, o agente aplicou uma sanção que Paula entende violar os princípios basilares da matéria. No tocante a Competência Ambiental, assinale a alternativa juridicamente correta:', 
  ARRAY['"A conduta é válida pois respeita estritamente as regras de Competência Ambiental previstas em lei específica."', '"A medida padece de nulidade absoluta por vício formal no tratamento de Competência Ambiental."', '"O instituto de Competência Ambiental não se aplica a entidades de direito público, apenas a relações privadas."', '"Configura-se desvio de finalidade por ausência de nexo causal no âmbito de Competência Ambiental."'], 
  0, 
  'No caso concreto, a conduta atende aos preceitos da legislação vigente aplicável a Competência Ambiental, respeitando os limites da legalidade e os princípios gerais de direito.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Ambiental' LIMIT 1)
);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Competência Ambiental', 
  'Médio', 
  'O cidadão Gustavo buscou assessoria jurídica para solucionar um conflito relativo a Competência Ambiental envolvendo uma entidade privada. Diante das regras vigentes e da jurisprudência consolidada, qual a orientação adequada a ser prestada a Gustavo?', 
