  2, 
  'A obrigação em Competência Ambiental possui caráter pessoal e segue a regra geral de distribuição do ônus probatório, exigindo prova do nexo de causalidade direto.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Ambiental' LIMIT 1)
);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
