  'A jurisprudência pátria estabelece que a disciplina jurídica de Competência Ambiental visa garantir a segurança jurídica e a eficiência das relações contratuais ou sociais pactuadas.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito Ambiental' LIMIT 1)
);
