INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Responsabilidade pelo Vício do Produto', 
  'Médio', 
  'Em recente acórdão, discutiu-se a aplicação das regras de Responsabilidade pelo Vício do Produto em caso de grande repercussão nacional. À luz da doutrina majoritária e da legislação aplicável, assinale a afirmativa correta:', 
