);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Responsabilidade pelo Vício do Produto', 
  'Médio', 
  'A administração ou a parte interessada, representada pelo doutor André, ajuizou a medida cabível para garantir o direito pretendido sobre Responsabilidade pelo Vício do Produto. Diante disso, assinale a opção correta:', 
  ARRAY['"A pretensão está amparada na legalidade e na doutrina clássica aplicável a Responsabilidade pelo Vício do Produto."', '"O direito caducou no prazo de cinco anos contados da ciência do fato referente a Responsabilidade pelo Vício do Produto."', '"Não cabe ação rescisória para reformar julgado fundamentado na interpretação de Responsabilidade pelo Vício do Produto."', '"A decisão administrativa faz coisa julgada material em relação a Responsabilidade pelo Vício do Produto, impedindo revisão judicial."'], 
  0, 
  'O prazo decadencial aplicável ao caso é quinquenal, conforme expressa previsão legal, aplicando-se de forma direta sobre os atos decorrentes de Responsabilidade pelo Vício do Produto.', 
  (SELECT id FROM disciplinas WHERE nome = 'Direito do Consumidor' LIMIT 1)
);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
