);
INSERT INTO questoes (tema, nivel, enunciado, alternativas, gabarito, explicacao, materia_id) 
VALUES (
  'Teoria Tridimensional do Direito', 
  'Médio', 
  'Em ação judicial discutindo especificamente o instituto de Teoria Tridimensional do Direito, a empresa X Ltda sustentou a inexigibilidade da obrigação alegada. Diante do quadro fático apresentado, assinale a opção que reflete o posicionamento correto sobre o tema:', 
